               - (SELECT overall_rating FROM Player_Attributes pa2 WHERE pa2.player_api_id = (SELECT player_api_id FROM Player WHERE player_name = 'Paulin Puel' LIMIT 1))
              ) AS REAL) * 100.0 / (SELECT overall_rating FROM Player_Attributes pa2 WHERE pa2.player_api_id = (SELECT player_api_id FROM Player WHERE player_name = 'Paulin Puel' LIMIT 1)) AS percentage_higher;	----- bird -----	european_football_2
